use strict; use warnings;
use utf8;
binmode STDOUT, ':encoding(UTF-8)';

my %descs = (
  2199 => 'Кліщі для обтиску наконечників Reliance REL5006, перетин 2.5–6мм². Змінний мультидайс з 13 гніздами, знімний фіксатор, точне дозусилля. Для штирьових та кільцевих наконечників.',
  2203 => 'Кліщі для обтиску мережевих кабелів Reliance RE15080 (8P8C/RJ-45, 6P6C/RJ-12, 6P4C/RJ-11). Зарізання контактів, відрізання та зачищення кабелю. Для монтажу комп\'ютерних і телефонних мереж.',
  2205 => 'Кліщі для обтиску мережевих кабелів Reliance RE15082 (8P8C/RJ-45, 6P6C/RJ-12, 6P4C/RJ-11). Потрійна функція: зарізання, відрізання, зачищення. Ергономічні ручки з гумовими вставками.',
  2606 => 'Ножиці для різання кабельного каналу Reliance REL 89. Точний рівний зріз пластикових кабель-каналів шириною до 89мм. Ріжучий механізм з поверхневим загартуванням, зручні ергономічні ручки.',
  4639 => 'Гільза з\'єднувальна ізольована з оловом Reliance 0.5–1.5мм², червона. Термоусаджувальна оболонка з клейовим шаром забезпечує герметичне з\'єднання та захист від вологи та корозії.',
  4640 => 'Гільза з\'єднувальна ізольована з оловом Reliance 1.5–2.5мм², синя. Термоусаджувальна оболонка з клейовим шаром забезпечує герметичне з\'єднання та захист від вологи та корозії.',
  4642 => 'Гільза з\'єднувальна ізольована з оловом Reliance 4–6мм², жовта. Термоусаджувальна оболонка з клейовим шаром забезпечує герметичне з\'єднання та захист від вологи та корозії.',
  4548 => 'Фотоелемент Feron LXP03/SEN27 білий, 25А/IP44. Автоматичне вмикання освітлення в темряві. Поріг спрацювання 1–80 Лк, витримка 30сек–10хв. Для зовнішнього та внутрішнього монтажу.',
  4669 => 'Датчик руху Feron SEN127 з цоколем Е27, 360°, дальність до 6м, IP20. Вкручується замість лампи — не потребує окремого монтажу. 1200Вт, 230В. Регулювання часу та порогу освітленості.',
  4675 => 'Фотоелемент Feron SEN25 білий, 6А/IP44. Автоматичне вмикання зовнішнього освітлення при настанні темряви. Поріг спрацювання регулюється. Монтаж на відкритій поверхні, клемне підключення.',
  4677 => 'Фотоелемент Feron LXP02/SEN26 білий, 10А/IP44. Автоматичне керування освітленням по рівню освітленості. Підвищений струм для більшого навантаження. Монтаж на відкритій поверхні, клемне підключення.',
  4827 => 'Наконечник штирьовий мідний без ізоляції НШВМ 10–12 Reliance. Для підключення багатожильного проводу 10мм² до клемних колодок та автоматів. Луджена мідь, щільне обтиснення.',
  4829 => 'Наконечник штирьовий мідний без ізоляції НШВМ 16–13 Reliance. Для підключення багатожильного проводу 16мм² до клемних колодок та автоматів. Луджена мідь, щільне обтиснення.',
  4839 => 'Наконечник кільцевий силовий мідний SC 2.5–5 без ізоляції. Перетин 2.5мм², довжина трубчастої частини 5мм. Для підключення до болтових клем і шин. Луджена електролітична мідь.',
  5172 => 'Термоусаджувальна трубка з клейовим шаром Reliance 12.7мм, коефіцієнт усадки 3:1. Внутрішній клейовий шар герметизує з\'єднання, захищає від вологи та корозії. Для ізоляції кабелів та муфт.',
  5178 => 'Термоусаджувальна трубка з клейовим шаром Reliance 2.4мм, коефіцієнт усадки 3:1. Захист кабельних з\'єднань від вологи, мастил та корозії. Температура усадки від 80°С, робоча -45…+125°С.',
  5180 => 'Термоусаджувальна трубка з клейовим шаром Reliance 25.4мм, коефіцієнт усадки 3:1. Для герметизації великих кабельних з\'єднань та муфт. Внутрішній клейовий шар забезпечує IP-захист.',
  5182 => 'Термоусаджувальна трубка з клейовим шаром Reliance 3.2мм, коефіцієнт усадки 3:1. Герметизація та ізоляція кабельних з\'єднань. Внутрішній клейовий шар активується при нагріванні.',
  5184 => 'Термоусаджувальна трубка з клейовим шаром Reliance 4.8мм, коефіцієнт усадки 3:1. Герметизація та ізоляція кабельних з\'єднань. Внутрішній клейовий шар активується при нагріванні.',
  5186 => 'Термоусаджувальна трубка з клейовим шаром Reliance 6.4мм, коефіцієнт усадки 3:1. Герметизація та ізоляція кабельних з\'єднань. Внутрішній клейовий шар активується при нагріванні.',
  5188 => 'Термоусаджувальна трубка з клейовим шаром Reliance 7.9мм, коефіцієнт усадки 3:1. Герметизація та ізоляція кабельних з\'єднань. Внутрішній клейовий шар активується при нагріванні.',
  5190 => 'Термоусаджувальна трубка з клейовим шаром Reliance 9.5мм, коефіцієнт усадки 3:1. Герметизація та ізоляція кабельних з\'єднань. Внутрішній клейовий шар активується при нагріванні.',
  5206 => 'Термоусаджувальна трубка Reliance 2.5/1.25мм, коефіцієнт усадки 2:1. Стандартна ізоляційна трубка без клею для захисту кабельних з\'єднань від механічних пошкоджень та вологи. Матеріал: поліолефін.',
);

open(my $in, '<:encoding(UTF-8)', 'js/data.js') or die $!;
my @lines = <$in>;
close $in;

my $ok = 0;
for my $ln (sort { $a <=> $b } keys %descs) {
  my $idx = $ln - 1;
  my $text = $descs{$ln};
  if ($lines[$idx] =~ s/desc:".*?",stock:/desc:"$text",stock:/) { $ok++; }
  else { print "WARN line $ln not matched\n"; }
}

open(my $out, '>:encoding(UTF-8)', 'js/data.js') or die $!;
print $out @lines;
close $out;
print "done, fixed $ok of " . scalar(keys %descs) . "\n";
